namespace sv_fd45d680866148da84afb57580d2867a.Services;

/// <summary>
/// Holds the currently selected warehouse for a single circuit (user session).
/// Registered as Scoped so each Blazor Server circuit gets its own instance.
/// </summary>
public sealed class WarehouseStateService
{
    public static readonly IReadOnlyList<(string Id, string Name)> AvailableWarehouses =
    [
        ("WH-A", "Warehouse A"),
        ("WH-B", "Warehouse B"),
        ("WH-C", "Warehouse C"),
    ];

    private string _currentWarehouseId = AvailableWarehouses[0].Id;

    public string CurrentWarehouseId => _currentWarehouseId;

    public string CurrentWarehouseName =>
        AvailableWarehouses.First(w => w.Id == _currentWarehouseId).Name;

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId)
            return;

        _currentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

namespace sv_fd45d680866148da84afb57580d2867a.Services;

/// <summary>
/// Manages low-stock alert polling. Scoped per circuit so each user has
/// independent alert counts and polling lifecycle.
/// </summary>
public sealed class InventoryAlertService : IDisposable
{
    private readonly WarehouseStateService _warehouseState;
    private readonly Random _random = new();
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private int _subscriberCount;

    public int LowStockCount { get; private set; }

    /// <summary>
    /// Fired on the calling synchronization context (Blazor dispatcher)
    /// whenever new alert data arrives so all subscribed components can re-render.
    /// </summary>
    public event Func<Task>? OnAlertDataChanged;

    public InventoryAlertService(WarehouseStateService warehouseState)
    {
        _warehouseState = warehouseState;
    }

    /// <summary>Simulates a database query returning a random low-stock count.</summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Called by components that want polling to be active.
    /// Polling starts on the first subscriber and stops when the last unsubscribes.
    /// </summary>
    public async Task StartPollingAsync()
    {
        _subscriberCount++;
        if (_subscriberCount == 1)
        {
            _cts = new CancellationTokenSource();
            _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
            // Fetch immediately on start
            await RefreshAsync();
            _ = PollLoopAsync(_cts.Token);
        }
    }

    public void StopPolling()
    {
        _subscriberCount = Math.Max(0, _subscriberCount - 1);
        if (_subscriberCount == 0)
        {
            _cts?.Cancel();
            _timer?.Dispose();
            _timer = null;
            _cts?.Dispose();
            _cts = null;
        }
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        try
        {
            while (_timer is not null && await _timer.WaitForNextTickAsync(ct))
            {
                await RefreshAsync();
            }
        }
        catch (OperationCanceledException)
        {
            // Expected on dispose / stop
        }
    }

    private async Task RefreshAsync()
    {
        LowStockCount = await GetLowStockCountAsync(_warehouseState.CurrentWarehouseId);
        if (OnAlertDataChanged is not null)
            await OnAlertDataChanged.Invoke();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _timer?.Dispose();
        _cts?.Dispose();
    }
}

