@using sv_fd45d680866148da84afb57580d2867a.Services
@rendermode InteractiveServer
@inject WarehouseStateService WarehouseState
@implements IDisposable

<select class="form-select form-select-sm"
        style="width: auto; display: inline-block;"
        value="@WarehouseState.CurrentWarehouseId"
        @onchange="OnWarehouseChanged">
    @foreach (var wh in WarehouseStateService.AvailableWarehouses)
    {
        <option value="@wh.Id">@wh.Name</option>
    }
</select>

@code {
    protected override void OnInitialized()
    {
        WarehouseState.OnChange += StateHasChanged;
    }

    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        WarehouseState.SetWarehouse(e.Value?.ToString() ?? "");
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= StateHasChanged;
    }
}

@using sv_fd45d680866148da84afb57580d2867a.Services
@rendermode InteractiveServer
@inject InventoryAlertService AlertService
@implements IDisposable

<span class="badge rounded-pill @BadgeClass">@AlertService.LowStockCount</span>

@code {
    private string BadgeClass =>
        AlertService.LowStockCount > 0 ? "bg-danger" : "bg-success";

    protected override void OnInitialized()
    {
        AlertService.OnAlertDataChanged += OnAlertDataChangedAsync;
    }

    private async Task OnAlertDataChangedAsync()
    {
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        AlertService.OnAlertDataChanged -= OnAlertDataChangedAsync;
    }
}

