@page "/dashboard"
@using sv_fd45d680866148da84afb57580d2867a.Services
@rendermode InteractiveServer
@inject WarehouseStateService WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>
<p class="text-muted">
    Currently viewing: <strong>@WarehouseState.CurrentWarehouseName</strong>
</p>

<div class="card mt-3" style="max-width: 400px;">
    <div class="card-body">
        <h5 class="card-title">Low-Stock Alerts</h5>
        <p class="card-text display-4">
            <span class="badge @BadgeClass">@AlertService.LowStockCount</span>
        </p>
        <p class="text-muted small">
            Items below minimum stock level. Refreshes every 10 seconds.
        </p>
    </div>
</div>

@code {
    private string BadgeClass =>
        AlertService.LowStockCount > 0 ? "bg-danger" : "bg-success";

    protected override async Task OnInitializedAsync()
    {
        WarehouseState.OnChange += OnWarehouseChanged;
        AlertService.OnAlertDataChanged += OnAlertDataChangedAsync;
        await AlertService.StartPollingAsync();
    }

    private void OnWarehouseChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    private async Task OnAlertDataChangedAsync()
    {
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= OnWarehouseChanged;
        AlertService.OnAlertDataChanged -= OnAlertDataChangedAsync;
        AlertService.StopPolling();
    }
}

